// src/components/AudioPlayer.js
import React, { useEffect, useState } from 'react';
import ReactAudioPlayer from 'react-audio-player';
import { PlayIcon } from '@heroicons/react/24/solid';

const AudioPlayer = ({ slug }) => {
  const [audioExists, setAudioExists] = useState(false);
  const [showAudioPlayer, setShowAudioPlayer] = useState(false);
  const audioSrc = `/audio/${slug}.mp3`;

  useEffect(() => {
    // Check if the audio file exists
    const audio = new Audio(audioSrc);
    audio.oncanplaythrough = () => setAudioExists(true);
    audio.onerror = () => setAudioExists(false);
  }, [audioSrc]);

  const handlePlayButtonClick = () => {
    setShowAudioPlayer(true);
  };

  return (
    <>
      {audioExists && !showAudioPlayer && (
        <div className="text-to-speech">
          <button onClick={handlePlayButtonClick}><PlayIcon className="h-6 w-6 text-gray-700 mr-2" />
          Play</button>
        </div>
      )}
      {showAudioPlayer && <ReactAudioPlayer src={audioSrc} autoPlay controls />}
    </>
  );
};

export default AudioPlayer;
